OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page

//   if(IsProject()==0)   int textMode=0;

   int textMode=0;



int krz=0;

int pozNeg=0;

int curSound=0;



   LoadGroup("Cursors.grp");



//#############################################################################

   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   int txtHotSpotOn=0;

   int playStatus=0;

   int puzzleNo=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

//############################################################################





SetCursor(0);

Transparent_Video_Holder.HideFirsLastVideoFrame(7);

Transparent_Video_Holder.HideFirsLastVideoFrame(8);

Transparent_Video_Holder.HideFirsLastVideoFrame(9);

Transparent_Video_Holder.HideFirsLastVideoFrame(10);

Transparent_Video_Holder.HideFirsLastVideoFrame(11);

Transparent_Video_Holder.HideFirsLastVideoFrame(12);

Transparent_Video_Holder.HideFirsLastVideoFrame(13);



   Sound_Holder.PlayDSound(1);

   SetTextMode();

   FadeScreen(1,1000);

//   SetTimer(5000);

}





void OnClosePage(void)

{

	// Add your close page handler code here



}





void SetTextMode(void)

{

   if(textMode)

   {

      playStatus = 1;

      Transparent_Video_Holder.Stop();

      Sound_Holder.SetPlayDSoundParameters(1,-1000,0,0);

      Sound_Holder.SetPlayDSoundParameters(10,-1000,0,0);

      Sound_Holder.PlayDSound(0);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

   }

   else

   {

      playStatus = 0;

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(1,0,0,0);

      Sound_Holder.SetPlayDSoundParameters(10,0,0,0);

   }

}



void Transparent_Video_Holder.MouseClickOnDown(int videoID)

{

   if(textMode)   return;



   if(videoID>=7)

   {

      if(curSound>=7)    Sound_Holder.Stop(curSound);

      curSound=videoID-4;

      Sound_Holder.PlayDSound(curSound);

   }

   switch(videoID)

   {

      case 0:

      case 3:

      case 7:

      case 10:

         if(krz)

         {

            krz=0;

            if(pozNeg)

            {

               Transparent_Video_Holder.Play(10,0);

               Transparent_Video_Holder.HideFirsLastVideoFrame(7);

            }

            else

            {

               Transparent_Video_Holder.Play(3,0);

               Transparent_Video_Holder.HideFirsLastVideoFrame(0);

            }

         }

         else

         {

            krz=1;

            if(pozNeg)

            {

               Transparent_Video_Holder.Play(7,0);

               Transparent_Video_Holder.HideFirsLastVideoFrame(10);

            }

            else

            {

               Transparent_Video_Holder.Play(0,0);

               Transparent_Video_Holder.HideFirsLastVideoFrame(3);

            }

         }

         break;

      case 4:

         Transparent_Video_Holder.SetDeep(videoID,4);

         Transparent_Video_Holder.SetDeep(5,1);

         Transparent_Video_Holder.Play(videoID,0);

         break;

      case 5:

         Transparent_Video_Holder.SetDeep(videoID,4);

         Transparent_Video_Holder.SetDeep(4,1);

         Transparent_Video_Holder.Play(videoID,0);

         break;

      case 11:

         Transparent_Video_Holder.SetDeep(videoID,4);

         Transparent_Video_Holder.SetDeep(12,1);

         Transparent_Video_Holder.ResetVideo(12);

         Transparent_Video_Holder.Play(videoID,0);

         break;

      case 12:

         Transparent_Video_Holder.SetDeep(videoID,4);

         Transparent_Video_Holder.SetDeep(11,3);

         Transparent_Video_Holder.Play(videoID,0);

         break;

      default:

         Transparent_Video_Holder.Play(videoID,0);

         break;

   }

}









void Transparent_Video_Holder.MouseMoveIn(int videoID)

{

   if(textMode==0)   SetCursor(1);

}





void Transparent_Video_Holder.MouseMoveOut(int videoID)

{

   SetCursor(0);

}





void Transparent_Video_Holder.TheEnd(int videoID)

{

   if(textMode)   return;

}





void HotSpot_Holder.MouseMoveIn(int rectID)

{

   if(textMode==0)   SetCursor(1);

}





void HotSpot_Holder.MouseMoveOut(int rectID)

{

   SetCursor(0);

}





void HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   if(textMode)   return;

   Transparent_Video_Holder.Stop();

   DisableScreen();

   Sound_Holder.StopAll();

   Sound_Holder.PlayDSound(2);

   if(pozNeg)

   {

      Sound_Holder.PlayDSound(1);

      Bitmap_Holder.ShowBitmap(0);

      Bitmap_Holder.HideBitmap(1);

      Transparent_Video_Holder.HideFirsLastVideoFrame(7);

      Transparent_Video_Holder.HideFirsLastVideoFrame(8);

      Transparent_Video_Holder.HideFirsLastVideoFrame(9);

      Transparent_Video_Holder.HideFirsLastVideoFrame(10);

      Transparent_Video_Holder.HideFirsLastVideoFrame(11);

      Transparent_Video_Holder.HideFirsLastVideoFrame(12);

      Transparent_Video_Holder.HideFirsLastVideoFrame(13);



      Transparent_Video_Holder.ShowFirsLastVideoFrame(0);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(1);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(2);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(3);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(4);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(5);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(6);

      pozNeg=0;

   }

   else

   {

      curSound=0;

      Sound_Holder.PlayDSound(10);

      Bitmap_Holder.ShowBitmap(1);

      Bitmap_Holder.HideBitmap(0);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(7);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(8);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(9);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(10);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(11);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(12);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(13);



      Transparent_Video_Holder.HideFirsLastVideoFrame(0);

      Transparent_Video_Holder.HideFirsLastVideoFrame(1);

      Transparent_Video_Holder.HideFirsLastVideoFrame(2);

      Transparent_Video_Holder.HideFirsLastVideoFrame(3);

      Transparent_Video_Holder.HideFirsLastVideoFrame(4);

      Transparent_Video_Holder.HideFirsLastVideoFrame(5);

      Transparent_Video_Holder.HideFirsLastVideoFrame(6);

      pozNeg=1;

   }

   krz=0;

   EnableScreen();

   ShowBuffer();

}



